import{_ as a,o,c as n,aQ as t}from"./chunks/framework.cDvftfeu.js";const p=JSON.parse('{"title":"User Center","description":"Manage your Ham account and settings.","frontmatter":{"description":"Manage your Ham account and settings."},"headers":[],"relativePath":"en/handbook/user-center.md","filePath":"en/handbook/user-center.md","lastUpdated":1777525243000}'),i={name:"en/handbook/user-center.md"};function r(s,e,c,l,u,d){return o(),n("div",null,[...e[0]||(e[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /handbook/user-center.md for this page in Markdown format</div><h1 id="user-center" tabindex="-1">User Center <a class="header-anchor" href="#user-center" aria-label="Permalink to &quot;User Center&quot;">​</a></h1><p>After logging in to your Ham account, you can manage your account information and settings in the User Center.</p><h2 id="ham-account" tabindex="-1">Ham Account <a class="header-anchor" href="#ham-account" aria-label="Permalink to &quot;Ham Account&quot;">​</a></h2><p>Ham supports the following login methods:</p><ul><li>Passkey</li><li>QQ</li><li>WeChat</li><li>GitHub</li><li>Ziqiang Auth</li><li>Apple Sign-In (iOS only)</li></ul><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><p>After logging in, you can change your avatar and nickname in the User Center.</p><h2 id="login-devices" tabindex="-1">Login Devices <a class="header-anchor" href="#login-devices" aria-label="Permalink to &quot;Login Devices&quot;">​</a></h2><p>You can view the list of currently logged-in devices and remove any devices you no longer use.</p><h2 id="social-accounts" tabindex="-1">Social Accounts <a class="header-anchor" href="#social-accounts" aria-label="Permalink to &quot;Social Accounts&quot;">​</a></h2><p>You can view your linked social accounts, link new ones, or unlink existing ones. The supported social account types are the same as the login methods.</p><h2 id="passkey-management" tabindex="-1">Passkey Management <a class="header-anchor" href="#passkey-management" aria-label="Permalink to &quot;Passkey Management&quot;">​</a></h2><p>You can manage your Passkeys here, including adding new Passkeys or removing existing ones. Passkey is a passwordless login method that uses your device&#39;s biometric authentication (such as Face ID or fingerprint) for identity verification.</p><h2 id="qr-code-login" tabindex="-1">QR Code Login <a class="header-anchor" href="#qr-code-login" aria-label="Permalink to &quot;QR Code Login&quot;">​</a></h2><p>You can use the app to scan a login QR code on Ham Web to quickly log in.</p><h2 id="authorized-apps" tabindex="-1">Authorized Apps <a class="header-anchor" href="#authorized-apps" aria-label="Permalink to &quot;Authorized Apps&quot;">​</a></h2><p>You can view and manage third-party apps that have been authorized to log in with your Ham account. If you no longer use an app, you can revoke its authorization.</p><h2 id="more" tabindex="-1">More <a class="header-anchor" href="#more" aria-label="Permalink to &quot;More&quot;">​</a></h2><p>In &quot;More,&quot; you can perform actions such as account deactivation.</p>',20)])])}const m=a(i,[["render",r]]);export{p as __pageData,m as default};
